/* Normalize x-height for better visual consistency across fonts */
body {
  font-family: 'Open Sans', sans-serif;
  font-size: 16px;
  font-size-adjust: 0.52; /* Example: Open Sans aspect value, aim for a common value */
}

h1, h2, h3 {
  font-family: 'Merriweather', serif;
  /* Adjust Merriweather to visually match Open Sans' x-height */
  font-size-adjust: 0.52; /* Apply the same desired aspect value */
  /* Note: You may still need to adjust font-size slightly for overall hierarchy */
}

/* How to find an approximate aspect value:
   aspect-value = x-height / font-size
   Use font inspection tools (e.g., in browser dev tools or font analysis software)
   to determine this ratio for your chosen fonts. Common values range from 0.48 to 0.52.
*/
